export function LogoCloud() {
  return (
    <section className="py-16 sm:py-20 overflow-hidden">
      <motion.div
        initial={{ opacity: 0 }}
        whileInView={{ opacity: 1 }}
        viewport={{ once: true }}
        className="text-center mb-10 px-4"
      >
        <p className="text-[10px] text-zinc-500 uppercase font-bold tracking-[0.2em]">
          Trusted by teams at leading organizations
        </p>
      </motion.div>

      <Marquee speed={40} gradient={false} pauseOnHover>
        {partners.map((partner) => (
          <div
            key={partner.name}
            className="mx-8 sm:mx-12 flex items-center justify-center select-none"
          >
            {partner.logo}
          </div>
        ))}
      </Marquee>
    </section>
  )
}
